27		jsonpatch "github.com/evanphx/json-patch/v5"
28		"github.com/go-openapi/jsonpointer"
29		corev1 "k8s.io/api/core/v1"
30		"k8s.io/apimachinery/pkg/apis/meta/v1/unstructured"
31		"k8s.io/client-go/tools/record"
32		"k8s.io/klog/v2"
