34		"sigs.k8s.io/controller-runtime/pkg/client"
35		"sigs.k8s.io/yaml"
36	
37		clusterv1alpha1 "github.com/karmada-io/karmada/pkg/apis/cluster/v1alpha1"
38		policyv1alpha1 "github.com/karmada-io/karmada/pkg/apis/policy/v1alpha1"
39		"github.com/karmada-io/karmada/pkg/events"
40		"github.com/karmada-io/karmada/pkg/util"
41	)
42	
43	const (
44		// OverrideManagerName is the manager name that will be used when reporting events.
45		OverrideManagerName = "override-manager"
46	)
47	
48	// OverrideManager managers override policies operation
49	type OverrideManager interface {
50		// ApplyOverridePolicies overrides the object if one or more override policies exist and matches the target cluster.
51		// For cluster scoped resource:
52		// - Apply ClusterOverridePolicy by policies name in ascending
53		// For namespaced scoped resource, apply order is:
54		// - First apply ClusterOverridePolicy;
55		// - Then apply OverridePolicy;
56		ApplyOverridePolicies(rawObj *unstructured.Unstructured, cluster string) (appliedClusterPolicies *AppliedOverrides, appliedNamespacedPolicies *AppliedOverrides, err error)
57	}
58	
59	// GeneralOverridePolicy is an abstract object of ClusterOverridePolicy and OverridePolicy
60	type GeneralOverridePolicy interface {
61		// GetName returns the name of OverridePolicy
62		GetName() string
63		// GetNamespace returns the namespace of OverridePolicy
64		GetNamespace() string
65		// GetOverrideSpec returns the OverrideSpec of OverridePolicy
66		GetOverrideSpec() policyv1alpha1.OverrideSpec
67	}
68	
69	// overrideOption define the JSONPatch operator
70	type overrideOption struct {
71		Op    string `json:"op"`
72		Path  string `json:"path"`
73		Value any    `json:"value,omitempty"`
74	}
75	
76	type policyOverriders struct {
77		name       string
78		namespace  string
79		overriders policyv1alpha1.Overriders
80	}
81	
82	type overrideManagerImpl struct {
83		client.Client
84		record.EventRecorder
85	}
86	
87	// New builds an OverrideManager instance.
88	func New(client client.Client, eventRecorder record.EventRecorder) OverrideManager {
89		return &overrideManagerImpl{
90			Client:        client,
91			EventRecorder: eventRecorder,
92		}
93	}
94	
95	func (o *overrideManagerImpl) ApplyOverridePolicies(rawObj *unstructured.Unstructured, clusterName string) (*AppliedOverrides, *AppliedOverrides, error) {
96		clusterObj := &clusterv1alpha1.Cluster{}
97		if err := o.Client.Get(context.TODO(), client.ObjectKey{Name: clusterName}, clusterObj); err != nil {
98			klog.Errorf("Failed to get member cluster: %s, error: %v", clusterName, err)
99			return nil, nil, err
100		}
101	
102		var appliedClusterOverrides *AppliedOverrides
103		var appliedNamespacedOverrides *AppliedOverrides
104		var err error
105	
106		// Apply cluster scoped override policies
107		appliedClusterOverrides, err = o.applyClusterOverrides(rawObj, clusterObj)
108		if err != nil {
109			klog.Errorf("Failed to apply cluster override policies. error: %v", err)
110			return nil, nil, err
111		}
112	
113		// For namespace scoped resources, should apply override policies under the same namespace.
114		// No matter the resources propagated by ClusterPropagationPolicy or PropagationPolicy.
115		if len(rawObj.GetNamespace()) > 0 {
116			// Apply namespace scoped override policies
117			appliedNamespacedOverrides, err = o.applyNamespacedOverrides(rawObj, clusterObj)
118			if err != nil {
119				klog.Errorf("Failed to apply namespaced override policies. error: %v", err)
120				return nil, nil, err
121			}
122		}
123	
124		return appliedClusterOverrides, appliedNamespacedOverrides, nil
125	}
126	
127	// applyClusterOverrides will apply overrides according to ClusterOverridePolicy instructions.
128	func (o *overrideManagerImpl) applyClusterOverrides(rawObj *unstructured.Unstructured, cluster *clusterv1alpha1.Cluster) (*AppliedOverrides, error) {
129		// get all cluster-scoped override policies
130		policyList := &policyv1alpha1.ClusterOverridePolicyList{}
131		if err := o.Client.List(context.TODO(), policyList, &client.ListOptions{UnsafeDisableDeepCopy: ptr.To(true)}); err != nil {
132			klog.Errorf("Failed to list cluster override policies, error: %v", err)
133			return nil, err
134		}
135	
136		if len(policyList.Items) == 0 {
137			return nil, nil
138		}
139	
140		items := make([]GeneralOverridePolicy, 0, len(policyList.Items))
141		for i := range policyList.Items {
142			items = append(items, &policyList.Items[i])
143		}
144		matchingPolicyOverriders := o.getOverridersFromOverridePolicies(items, rawObj, cluster)
145		if len(matchingPolicyOverriders) == 0 {
146			klog.V(2).Infof("No cluster override policy for resource: %s/%s", rawObj.GetNamespace(), rawObj.GetName())
147			return nil, nil
148		}
149	
150		appliedList := &AppliedOverrides{}
151		for _, p := range matchingPolicyOverriders {
152			if err := applyPolicyOverriders(rawObj, p.overriders); err != nil {
153				klog.Errorf("Failed to apply cluster overrides(%s) for resource(%s/%s), error: %v", p.name, rawObj.GetNamespace(), rawObj.GetName(), err)
154				o.EventRecorder.Eventf(rawObj, corev1.EventTypeWarning, events.EventReasonApplyOverridePolicyFailed, "Apply cluster override policy(%s) for cluster(%s) failed.", p.name, cluster.Name)
155				return nil, err
156			}
157			klog.V(2).Infof("Applied cluster overrides(%s) for resource(%s/%s)", p.name, rawObj.GetNamespace(), rawObj.GetName())
158			o.EventRecorder.Eventf(rawObj, corev1.EventTypeNormal, events.EventReasonApplyOverridePolicySucceed, "Apply cluster override policy(%s) for cluster(%s) succeed.", p.name, cluster.Name)
159			appliedList.Add(p.name, p.overriders)
160		}
161	
162		return appliedList, nil
163	}
164	
165	// applyNamespacedOverrides will apply overrides according to OverridePolicy instructions.
166	func (o *overrideManagerImpl) applyNamespacedOverrides(rawObj *unstructured.Unstructured, cluster *clusterv1alpha1.Cluster) (*AppliedOverrides, error) {
167		// get all namespace-scoped override policies
168		policyList := &policyv1alpha1.OverridePolicyList{}
169		if err := o.Client.List(context.TODO(), policyList, &client.ListOptions{Namespace: rawObj.GetNamespace(), UnsafeDisableDeepCopy: ptr.To(true)}); err != nil {
170			klog.Errorf("Failed to list override policies from namespace: %s, error: %v", rawObj.GetNamespace(), err)
171			return nil, err
172		}
173	
174		if len(policyList.Items) == 0 {
175			return nil, nil
176		}
177	
178		items := make([]GeneralOverridePolicy, 0, len(policyList.Items))
179		for i := range policyList.Items {
180			items = append(items, &policyList.Items[i])
181		}
182		matchingPolicyOverriders := o.getOverridersFromOverridePolicies(items, rawObj, cluster)
183		if len(matchingPolicyOverriders) == 0 {
184			klog.V(2).Infof("No override policy for resource(%s/%s)", rawObj.GetNamespace(), rawObj.GetName())
185			return nil, nil
186		}
187	
188		appliedList := &AppliedOverrides{}
189		for _, p := range matchingPolicyOverriders {
190			if err := applyPolicyOverriders(rawObj, p.overriders); err != nil {
191				klog.Errorf("Failed to apply overrides(%s/%s) for resource(%s/%s), error: %v", p.namespace, p.name, rawObj.GetNamespace(), rawObj.GetName(), err)
192				o.EventRecorder.Eventf(rawObj, corev1.EventTypeWarning, events.EventReasonApplyOverridePolicyFailed, "Apply override policy(%s/%s) for cluster(%s) failed.", p.namespace, p.name, cluster.Name)
193				return nil, err
194			}
195			klog.V(2).Infof("Applied overrides(%s/%s) for resource(%s/%s)", p.namespace, p.name, rawObj.GetNamespace(), rawObj.GetName())
196			o.EventRecorder.Eventf(rawObj, corev1.EventTypeNormal, events.EventReasonApplyOverridePolicySucceed, "Apply override policy(%s/%s) for cluster(%s) succeed.", p.namespace, p.name, cluster.Name)
197			appliedList.Add(p.name, p.overriders)
198		}
199	
200		return appliedList, nil
201	}
202	
203	func (o *overrideManagerImpl) getOverridersFromOverridePolicies(policies []GeneralOverridePolicy, resource *unstructured.Unstructured, cluster *clusterv1alpha1.Cluster) []policyOverriders {
204		resourceMatchingPolicies := make([]GeneralOverridePolicy, 0)
205		for _, policy := range policies {
206			if len(policy.GetOverrideSpec().ResourceSelectors) == 0 {
207				resourceMatchingPolicies = append(resourceMatchingPolicies, policy)
208				continue
209			}
210	
211			if util.ResourceMatchSelectors(resource, policy.GetOverrideSpec().ResourceSelectors...) {
212				resourceMatchingPolicies = append(resourceMatchingPolicies, policy)
213			}
214		}
215		sort.SliceStable(resourceMatchingPolicies, func(i, j int) bool {
216			implicitPriorityI := util.ResourceMatchSelectorsPriority(resource, resourceMatchingPolicies[i].GetOverrideSpec().ResourceSelectors...)
217			if len(resourceMatchingPolicies[i].GetOverrideSpec().ResourceSelectors) == 0 {
218				implicitPriorityI = util.PriorityMatchAll
219			}
220			implicitPriorityJ := util.ResourceMatchSelectorsPriority(resource, resourceMatchingPolicies[j].GetOverrideSpec().ResourceSelectors...)
221			if len(resourceMatchingPolicies[j].GetOverrideSpec().ResourceSelectors) == 0 {
222				implicitPriorityJ = util.PriorityMatchAll
223			}
224			if implicitPriorityI != implicitPriorityJ {
225				return implicitPriorityI < implicitPriorityJ
226			}
227			return resourceMatchingPolicies[i].GetName() < resourceMatchingPolicies[j].GetName()
228		})
229		clusterMatchingPolicyOverriders := make([]policyOverriders, 0)
230		for _, policy := range resourceMatchingPolicies {
231			overrideRules := policy.GetOverrideSpec().OverrideRules
232			// Since the tuple of '.spec.TargetCluster' and '.spec.Overriders' can not co-exist with '.spec.OverrideRules'
233			// (guaranteed by webhook), so we only look '.spec.OverrideRules' here.
234			if len(overrideRules) == 0 {
235				overrideRules = []policyv1alpha1.RuleWithCluster{
236					{
237						//nolint:staticcheck
238						// disable `deprecation` check for backward compatibility.
239						TargetCluster: policy.GetOverrideSpec().TargetCluster,
240						//nolint:staticcheck
241						// disable `deprecation` check for backward compatibility.
242						Overriders: policy.GetOverrideSpec().Overriders,
243					},
244				}
245			}
246			for _, rule := range overrideRules {
247				if rule.TargetCluster == nil || (rule.TargetCluster != nil && util.ClusterMatches(cluster, *rule.TargetCluster)) {
248					clusterMatchingPolicyOverriders = append(clusterMatchingPolicyOverriders, policyOverriders{
249						name:       policy.GetName(),
250						namespace:  policy.GetNamespace(),
251						overriders: rule.Overriders,
252					})
253				}
254			}
255		}
256	
257		// select policy in which at least one PlaintextOverrider matches target resource.
258		// TODO(RainbowMango): check if the overrider instructions can be applied to target resource.
259	
260		return clusterMatchingPolicyOverriders
261	}
262	
263	// applyJSONPatch applies the override on to the given unstructured object.
264	func applyJSONPatch(obj *unstructured.Unstructured, overrides []overrideOption) error {
265		jsonPatchBytes, err := json.Marshal(overrides)
266		if err != nil {
267			return err
268		}
269	
270		patch, err := jsonpatch.DecodePatch(jsonPatchBytes)
271		if err != nil {
272			return err
273		}
274	
275		objectJSONBytes, err := obj.MarshalJSON()
276		if err != nil {
277			return err
278		}
279	
280		patchedObjectJSONBytes, err := patch.Apply(objectJSONBytes)
281		if err != nil {
282			return err
283		}
284	
285		err = obj.UnmarshalJSON(patchedObjectJSONBytes)
286		return err
287	}
288	
289	// applyRawJSONPatch applies the override on to the given raw json object.
290	func applyRawJSONPatch(raw []byte, overrides []overrideOption) ([]byte, error) {
291		jsonPatchBytes, err := json.Marshal(overrides)
292		if err != nil {
293			return nil, err
294		}
295	
296		patch, err := jsonpatch.DecodePatch(jsonPatchBytes)
297		if err != nil {
298			return nil, err
299		}
300	
301		return patch.Apply(raw)
302	}
303	
304	func applyRawYAMLPatch(raw []byte, overrides []overrideOption) ([]byte, error) {
305		rawJSON, err := yaml.YAMLToJSON(raw)
306		if err != nil {
307			klog.ErrorS(err, "Failed to convert yaml to json")
308			return nil, err
309		}
310	
311		jsonPatchBytes, err := json.Marshal(overrides)
312		if err != nil {
313			return nil, err
314		}
315	
316		patch, err := jsonpatch.DecodePatch(jsonPatchBytes)
317		if err != nil {
318			return nil, err
319		}
320	
321		rawJSON, err = patch.Apply(rawJSON)
322		if err != nil {
323			return nil, err
324		}
325	
326		rawYAML, err := yaml.JSONToYAML(rawJSON)
327		if err != nil {
328			klog.Errorf("Failed to convert json to yaml, error: %v", err)
329			return nil, err
330		}
331	
332		return rawYAML, nil
333	}
334	
335	// applyPolicyOverriders applies OverridePolicy/ClusterOverridePolicy overriders to target object
336	func applyPolicyOverriders(rawObj *unstructured.Unstructured, overriders policyv1alpha1.Overriders) error {
337		err := applyImageOverriders(rawObj, overriders.ImageOverrider)
338		if err != nil {
339			return err
340		}
341		// patch command
342		if err := applyCommandOverriders(rawObj, overriders.CommandOverrider); err != nil {
343			return err
344		}
345		// patch args
346		if err := applyArgsOverriders(rawObj, overriders.ArgsOverrider); err != nil {
347			return err
348		}
349		if err := applyLabelsOverriders(rawObj, overriders.LabelsOverrider); err != nil {
350			return err
351		}
352		if err := applyAnnotationsOverriders(rawObj, overriders.AnnotationsOverrider); err != nil {
353			return err
354		}
355		if err := applyFieldOverriders(rawObj, overriders.FieldOverrider); err != nil {
356			return err
357		}
358		return applyJSONPatch(rawObj, parseJSONPatchesByPlaintext(overriders.Plaintext))
359	}
360	
361	func applyImageOverriders(rawObj *unstructured.Unstructured, imageOverriders []policyv1alpha1.ImageOverrider) error {
362		for index := range imageOverriders {
363			patches, err := buildPatches(rawObj, &imageOverriders[index])
364			if err != nil {
365				klog.Errorf("Build patches with imageOverrides err: %v", err)
366				return err
367			}
368	
369			klog.V(4).Infof("Parsed JSON patches by imageOverriders(%+v): %+v", imageOverriders[index], patches)
370			if err = applyJSONPatch(rawObj, patches); err != nil {
371				return err
372			}
373		}
374	
375		return nil
376	}
377	
378	func applyCommandOverriders(rawObj *unstructured.Unstructured, commandOverriders []policyv1alpha1.CommandArgsOverrider) error {
379		for index := range commandOverriders {
380			patches, err := buildCommandArgsPatches(CommandString, rawObj, &commandOverriders[index])
381			if err != nil {
382				return err
383			}
384	
385			klog.V(4).Infof("Parsed JSON patches by commandOverriders(%+v): %+v", commandOverriders[index], patches)
386			if err = applyJSONPatch(rawObj, patches); err != nil {
387				return err
388			}
389		}
390	
391		return nil
392	}
393	
394	func applyArgsOverriders(rawObj *unstructured.Unstructured, argsOverriders []policyv1alpha1.CommandArgsOverrider) error {
395		for index := range argsOverriders {
396			patches, err := buildCommandArgsPatches(ArgsString, rawObj, &argsOverriders[index])
397			if err != nil {
398				return err
399			}
400	
401			klog.V(4).Infof("Parsed JSON patches by argsOverriders(%+v): %+v", argsOverriders[index], patches)
402			if err = applyJSONPatch(rawObj, patches); err != nil {
403				return err
404			}
405		}
406	
407		return nil
408	}
409	
410	func applyFieldOverriders(rawObj *unstructured.Unstructured, FieldOverriders []policyv1alpha1.FieldOverrider) error {
411		if len(FieldOverriders) == 0 {
412			return nil
413		}
414		for index := range FieldOverriders {
415			pointer, err := jsonpointer.New(FieldOverriders[index].FieldPath)
416			if err != nil {
417				klog.Errorf("Build jsonpointer with overrider's path err: %v", err)
418				return err
419			}
420			res, kind, err := pointer.Get(rawObj.Object)
421			if err != nil {
422				klog.Errorf("Get value by overrider's path err: %v", err)
423				return err
424			}
425			if kind != reflect.String {
426				errMsg := fmt.Sprintf("Get object's value by overrider's path(%s) is not string", FieldOverriders[index].FieldPath)
427				klog.Error(errMsg)
428				return errors.New(errMsg)
429			}
430			dataBytes := []byte(res.(string))
431			klog.V(4).Infof("Parsed JSON patches by FieldOverriders[%d](%+v)", index, FieldOverriders[index])
432			var appliedRawData []byte
433			if len(FieldOverriders[index].YAML) > 0 {
434				appliedRawData, err = applyRawYAMLPatch(dataBytes, parseYAMLPatchesByField(FieldOverriders[index].YAML))
435				if err != nil {
436					klog.Errorf("Error applying raw JSON patch: %v", err)
437					return err
438				}
439			} else if len(FieldOverriders[index].JSON) > 0 {
440				appliedRawData, err = applyRawJSONPatch(dataBytes, parseJSONPatchesByField(FieldOverriders[index].JSON))
441				if err != nil {
442					klog.Errorf("Error applying raw YAML patch: %v", err)
443					return err
444				}
445			}
446			_, err = pointer.Set(rawObj.Object, string(appliedRawData))
447			if err != nil {
448				return err
449			}
450		}
451		return nil
452	}
453	
454	func parseJSONPatchesByPlaintext(overriders []policyv1alpha1.PlaintextOverrider) []overrideOption {
455		patches := make([]overrideOption, 0, len(overriders))
456		for i := range overriders {
457			patches = append(patches, overrideOption{
458				Op:    string(overriders[i].Operator),
459				Path:  overriders[i].Path,
460				Value: overriders[i].Value,
461			})
462		}
463		return patches
464	}
465	
466	func parseYAMLPatchesByField(overriders []policyv1alpha1.YAMLPatchOperation) []overrideOption {
467		patches := make([]overrideOption, 0, len(overriders))
468		for i := range overriders {
469			patches = append(patches, overrideOption{
470				Op:    string(overriders[i].Operator),
471				Path:  overriders[i].SubPath,
472				Value: overriders[i].Value,
473			})
474		}
475		return patches
476	}
477	
478	func parseJSONPatchesByField(overriders []policyv1alpha1.JSONPatchOperation) []overrideOption {
479		patches := make([]overrideOption, 0, len(overriders))
480		for i := range overriders {
481			patches = append(patches, overrideOption{
482				Op:    string(overriders[i].Operator),
483				Path:  overriders[i].SubPath,
484				Value: overriders[i].Value,
485			})
486		}
487		return patches
488	}
